#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\askell\node_modules\.pnpm\moleculer@0.15.0_debug@4.4.3_nats@2.29.3\node_modules\moleculer\bin\node_modules;C:\askell\node_modules\.pnpm\moleculer@0.15.0_debug@4.4.3_nats@2.29.3\node_modules\moleculer\node_modules;C:\askell\node_modules\.pnpm\moleculer@0.15.0_debug@4.4.3_nats@2.29.3\node_modules;C:\askell\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/askell/node_modules/.pnpm/moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules/moleculer/bin/node_modules:/mnt/c/askell/node_modules/.pnpm/moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules/moleculer/node_modules:/mnt/c/askell/node_modules/.pnpm/moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules:/mnt/c/askell/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../../../../../moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules/moleculer/bin/moleculer-runner.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../../../../../moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules/moleculer/bin/moleculer-runner.js" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../../../../../moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules/moleculer/bin/moleculer-runner.js" $args
  } else {
    & "node$exe"  "$basedir/../../../../../moleculer@0.15.0_debug@4.4.3_nats@2.29.3/node_modules/moleculer/bin/moleculer-runner.js" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
